fun solve(nums: Array<Long>, k: Long): Long {
    val sorted = nums.sorted()
    var maxSubset = 1L
    for (i in 0 until sorted.size) {
        val target = sorted[i] * k
        var low = i
        var high = sorted.size - 1
        var best = i - 1
        while (low <= high) {
            val mid = (low + high) / 2
            if (sorted[mid] <= target) {
                best = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        val currentSize = best - i + 1
        if (currentSize > maxSubset) {
            maxSubset = currentSize.toLong()
        }
    }
    return (nums.size - maxSubset).toLong()
}
