fun solve(nums: Array<Long>, k: Long): Long {
    val n = nums.size
    if (n == 0) return 0L
    nums.sort()
    var maxLen = 1L
    for (i in 0 until n) {
        val target = nums[i] * k
        val pos = nums.upperBound(target)
        val j = pos - 1
        if (j >= i) {
            val currentLen = j - i + 1
            if (currentLen > maxLen) {
                maxLen = currentLen
            }
        }
    }
    return n - maxLen
}
